import { useState, useRef, useEffect } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const containerRef = useRef(null)

  const presetBoxes = {
    front: {
      x: 50,
      y: 42,
      size: 220
    },

    'left-chest': {
      x: 70,
      y: 31,
      size: 120
    },

    back: {
      x: 50,
      y: 42,
      size: 320
    }
  }

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const [logoSize, setLogoSize] = useState(
    presetBoxes.front.size
  )

  const [logoWarp, setLogoWarp] = useState(0)

  const [isDragging, setIsDragging] = useState(false)

  const [activePreset, setActivePreset] = useState('front')

  const [logoPosition, setLogoPosition] = useState({
    x: presetBoxes.front.x,
    y: presetBoxes.front.y
  })

  useEffect(() => {

    const handleKeyDown = (e) => {

      const step = 1

      if (e.key === 'ArrowUp') {
        setLogoPosition(prev => ({
          ...prev,
          y: prev.y - step
        }))
      }

      if (e.key === 'ArrowDown') {
        setLogoPosition(prev => ({
          ...prev,
          y: prev.y + step
        }))
      }

      if (e.key === 'ArrowLeft') {
        setLogoPosition(prev => ({
          ...prev,
          x: prev.x - step
        }))
      }

      if (e.key === 'ArrowRight') {
        setLogoPosition(prev => ({
          ...prev,
          x: prev.x + step
        }))
      }
    }

    window.addEventListener(
      'keydown',
      handleKeyDown
    )

    return () => {

      window.removeEventListener(
        'keydown',
        handleKeyDown
      )
    }

  }, [])

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (file) {

      setUploadedLogo(
        URL.createObjectURL(file)
      )

      setLogoPosition({
        x: presetBoxes[activePreset].x,
        y: presetBoxes[activePreset].y
      })

      setLogoSize(
        presetBoxes[activePreset].size
      )
    }
  }

  const removeLogo = () => {

    setUploadedLogo(null)
  }

  const resetLogo = () => {

    setLogoPosition({
      x: presetBoxes[activePreset].x,
      y: presetBoxes[activePreset].y
    })

    setLogoSize(
      presetBoxes[activePreset].size
    )

    setLogoWarp(0)
  }

  const handleMouseMove = (e) => {

    if (!isDragging) return

    const rect =
      containerRef.current.getBoundingClientRect()

    const x =
      ((e.clientX - rect.left) / rect.width) * 100

    const y =
      ((e.clientY - rect.top) / rect.height) * 100

    setLogoPosition({
      x,
      y
    })
  }

  const handleMouseUp = () => {
    setIsDragging(false)
  }

  const setPreset = (type) => {

    setActivePreset(type)

    setLogoPosition({
      x: presetBoxes[type].x,
      y: presetBoxes[type].y
    })

    setLogoSize(
      presetBoxes[type].size
    )
  }

  return (

    <div
      className="h-screen bg-black text-white overflow-hidden"
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
    >

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">

        <div
          ref={containerRef}
          className="bg-[#0a0a0a] flex items-center justify-center relative overflow-hidden"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[950px] scale-110"
          />

          {uploadedLogo && (

            <>
              <div
                className="absolute border-2 border-dashed border-yellow-500/40 pointer-events-none"
                style={{
                  width: `${logoSize}px`,
                  height: `${logoSize}px`,
                  top: `${logoPosition.y}%`,
                  left: `${logoPosition.x}%`,
                  transform: 'translate(-50%, -50%)'
                }}
              />

              <img
                src={uploadedLogo}
                alt="logo"
                onMouseDown={() => setIsDragging(true)}
                className="absolute z-20 select-none"
                style={{
                  width: `${logoSize}px`,
                  top: `${logoPosition.y}%`,
                  left: `${logoPosition.x}%`,
                  transform: `
                    translate(-50%, -50%)
                    perspective(900px)
                    rotateX(${logoWarp}deg)
                  `,
                  cursor: isDragging ? 'grabbing' : 'grab',
                  filter: `
                    contrast(1.03)
                    saturate(1.08)
                    brightness(1.02)
                  `
                }}
                draggable={false}
              />

              <div
                className="absolute bottom-6 left-6 bg-black/70 border border-[#222] px-4 py-2 rounded-xl text-xs font-black z-40"
              >
                X: {Math.round(logoPosition.x)}%
                {'  '}
                Y: {Math.round(logoPosition.y)}%
              </div>

            </>

          )}

        </div>

        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full overflow-y-auto">

          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>

          <div className="p-6 space-y-6">

            <div>

              <h2 className="text-sm font-black mb-4">
                Shirt Colors
              </h2>

              <div className="grid grid-cols-2 gap-3">

                {product.colors.map((color) => (

                  <button
                    key={color.name}
                    onClick={() => setSelectedColor(color)}
                    className={`p-4 rounded-xl text-xs font-black capitalize ${
                      selectedColor.name === color.name
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {color.name}
                  </button>

                ))}

              </div>

            </div>

            <div>

              <h2 className="text-sm font-black mb-4">
                Placement
              </h2>

              <div className="grid grid-cols-1 gap-3">

                {[
                  'front',
                  'left-chest',
                  'back'
                ].map((item) => (

                  <button
                    key={item}
                    onClick={() => setPreset(item)}
                    className={`p-4 rounded-xl text-xs font-black ${
                      activePreset === item
                        ? 'bg-yellow-500 text-black'
                        : 'bg-[#111] border border-[#222]'
                    }`}
                  >
                    {item}
                  </button>

                ))}

              </div>

            </div>

            <div>

              <h2 className="text-sm font-black mb-4">
                Upload Logo
              </h2>

              <input
                type="file"
                accept="image/png,image/jpeg"
                onChange={handleUpload}
                className="w-full bg-[#111] border border-[#222] rounded-xl p-4 text-sm"
              />

            </div>

            {uploadedLogo && (

              <>
                <button
                  onClick={removeLogo}
                  className="w-full border border-red-500 text-red-500 py-4 rounded-xl text-xs font-black"
                >

                  REMOVE LOGO

                </button>

                <button
                  onClick={resetLogo}
                  className="w-full bg-yellow-500 text-black py-4 rounded-xl text-xs font-black"
                >

                  RESET DESIGN

                </button>

              </>

            )}

            <div>

              <div className="flex justify-between mb-3">

                <p className="text-xs text-white/60">
                  Logo Size
                </p>

                <p className="text-xs text-yellow-500 font-black">
                  {logoSize}px
                </p>

              </div>

              <input
                type="range"
                min="60"
                max="700"
                value={logoSize}
                onChange={(e) =>
                  setLogoSize(e.target.value)
                }
                className="w-full"
              />

            </div>

            <div>

              <div className="flex justify-between mb-3">

                <p className="text-xs text-white/60">
                  Fabric Warp
                </p>

                <p className="text-xs text-yellow-500 font-black">
                  {logoWarp}°
                </p>

              </div>

              <input
                type="range"
                min="-20"
                max="20"
                value={logoWarp}
                onChange={(e) =>
                  setLogoWarp(e.target.value)
                }
                className="w-full"
              />

            </div>

          </div>

        </div>

      </div>

    </div>

  )
}
